import{_ as a,o,c as t,a3 as n}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"53. Annual Leave","description":"","frontmatter":{"title":"53. Annual Leave","eba":"Health Allied & Managers Admin 2021-2025","topics":["leave","annual-leave","hours","employment"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/leave/53-annual-leave.md","filePath":"ebas/has-managers-admin/common-terms/leave/53-annual-leave.md"}'),r={name:"ebas/has-managers-admin/common-terms/leave/53-annual-leave.md"};function s(l,e,i,p,h,d){return o(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="_53-annual-leave" tabindex="-1">53. Annual Leave <a class="header-anchor" href="#_53-annual-leave" aria-label="Permalink to &quot;53. Annual Leave&quot;">​</a></h1><p><strong>53.1</strong> Basic entitlement</p><p><strong>(a)</strong> An Employee (other than a casual Employee) is entitled to five weeks annual leave for each year of service with the Employer.</p><p><strong>(b)</strong> Part-time Employees will be entitled to annual leave on a pro rata basis.</p><p><strong>(c)</strong> An Employee’s annual leave accrues progressively during a year of service according to the Employee’s ordinary hours of work, and accrues from year to year.</p><p><strong>53.2</strong> Shiftworker Definition for NES Purposes For the purposes of the NES a shiftworker is an Employee who is regularly rostered to work Sundays and public holidays.</p><p><strong>53.3</strong> Weekend Worker Definition For the purposes of this clause, weekend worker means any Employee who in any one year of employment works a portion of his or her ordinary hours on a weekend.</p><p><strong>53.4</strong> Additional Week’s Annual Leave</p><p><strong>(a)</strong> An Employee who is a weekend worker who works for more than four ordinary hours on 10 or more weekends is entitled to an additional week’s annual leave on the same terms and conditions.</p><p><strong>(b)</strong> Where an Employee who is weekend worker does not meet the 10 weekend threshold in clause 53.4(a), they will accrue additional annual leave at the rate of one tenth of a week for each weekend worked, up to a maximum of one week in a year.</p><p><strong>(c)</strong> The provisions of this clause have the same effect and give an Employee an entitlement to annual leave that is the same as the entitlement of the Employee under the NES relating to shiftworkers under section 87(1)(b)(ii) of the Act.</p><p><strong>(d)</strong> An Employee’s entitlement to annual leave under this clause operates in parallel with the Employee’s NES entitlement, but not so as to give the Employee a double benefit.</p><p><strong>(e)</strong> A weekend worker whose employment is terminated at the end of a period of employment which is less than one year computed from the date of commencement of the employment, or the date upon which the Employee last became entitled to annual leave from the Employer, will be paid in addition to any other amounts due to the Employee, an amount equal to 1/48th of his or her ordinary pay in respect of that period of employment.</p><p><strong>53.5</strong> Taking of annual leave</p><p><strong>(a)</strong> Annual leave will be taken at a time or times as agreed between the Employer and Employee. Where an Employee requests a period of annual leave, agreement will not be unreasonably withheld by the Employer.</p><p><strong>(b)</strong> Where a public holiday occurs during a period when an Employee is on annual leave, the Employee is taken not to be on annual leave on that public holiday.</p><p><strong>(c)</strong> If the period during which an Employee takes paid annual leave includes a period of any other leave (other than unpaid parental leave), or a period of absence from employment in accordance with <a href="/eba/ebas/has-managers-admin/common-terms/leave/62-leave-to-engage-in-voluntary-emergency.html">clauses 62</a>, 63, and 64, and the Employee is taken not to be on paid annual leave for the period of that other leave or absence.</p><p><strong>(d)</strong> The amount of annual leave loading or penalties paid to an Employee in accordance with subclause 53.7 in respect of a period of annual leave that is subsequently converted to another type of leave will be deducted from any future entitlement under subclause</p><p><strong>53.1</strong> or payment upon termination of employment, where applicable.</p><p><strong>(e)</strong> The Employer and an Employee may agree to defer the payment of annual leave loading in respect of single day annual leave absences until at least five annual leave days are taken by the Employee.</p><p><strong>(f)</strong> No Manager or Administrative Worker will be recalled from annual leave, other than by mutual agreement between the Employer and Manager or Administrative Worker. The Employer will reimburse the Manager or Administrative Worker for any expenses incurred by the Manager or Administrative Worker as a result of a return to duty from a period of annual leave. Unsatisfied leave arising from a recall to duty will be fulfilled as soon as possible thereafter, by agreement between the Employer and Manager or Administrative Worker.</p><p><strong>53.6</strong> Payment for annual leave</p><p><strong>(a)</strong> If an Employee takes a period of paid annual leave, the Employer must pay the Employee their ordinary pay for the period of leave so taken.</p><p><strong>(b)</strong> Ordinary pay, for the purposes of this clause, means remuneration for the Employee’s weekly number of hours during the period of leave taken, calculated at the ordinary time rate of pay pursuant to</p><p><strong>(c)</strong> If, when the employment of an Employee ends, the Employee has an accrued annual leave entitlement, the Employer must pay the Employee the amount that would have been payable to the Employee had they taken the period of accrued annual leave.</p><p><strong>(d)</strong> The Employer will pay each Manager or Administrative Worker in advance before the commencement of a period of annual leave, his or her ordinary pay for the leave period.</p><p><strong>(e)</strong> Notwithstanding subclause 53.6(d) above, Managers or Administrative Workers employed by Royal Women’s Hospital or Royal Children’s Hospital will be required to give four weeks written notice of a request for payment in advance. Such payment will only be made by the Employer where the period of annual leave exceeds two weeks in aggregate.</p><p><strong>53.7</strong> Annual Leave Loading Health and Allied Services Employees</p><p><strong>(a)</strong> In addition to the ordinary pay as described in subclause 53.6, Health and Allied Services Employees (other than Dental Assistants employed by DHSV or Ballarat Health Service) will receive either:</p><p><strong>(i)</strong> over Agreement payments for ordinary hours of work (where applicable);</p><p><strong>(ii)</strong> shift work allowances as set out in Section 1, subclauses</p><p><strong>45.1</strong> to 45.4, according to the roster or projected roster (where applicable);</p><p><strong>(iii)</strong> Weekend Work loadings as set out in Section 2, <a href="/eba/ebas/has-managers-admin/common-terms/employment-types/25-fixed-term-employment.html">clause 25</a>, according to the roster or projected roster (where applicable); and</p><p><strong>(iv)</strong> in-charge allowances (where applicable); or</p><p><strong>(v)</strong> annual leave loading equal to 17.5% of his or her wage, for his or her normal weekly hours, calculated at the ordinary time rate of pay, whichever is the higher.</p><p><strong>(b)</strong> Dental Assistants employed by DHSV or Ballarat Health Service are not eligible for payment of annual leave loading in addition to the ordinary pay as described in subclause 53.7 as the rates of pay for Dental Assistants employed by DHSV or Ballarat Health Service are inclusive of annual leave loading. Manager and Administrative Workers</p><p><strong>(c)</strong> In addition to the ordinary pay as described in subclause 53.6, Manager and Administrative Workers not employed by Royal Women’s Hospital or Royal Children’s Hospital will receive either:</p><p><strong>(i)</strong> Shift work allowances as set out in Section 1, subclauses</p><p><strong>45.1</strong> to 45.4 according to the roster or projected roster;</p><p><strong>(ii)</strong> Weekend Work loadings as set out in Section 3, <a href="/eba/ebas/allied-health/preliminary/9-no-extra-claims.html">clause 9</a> according to the roster or projected roster; or</p><p><strong>(iii)</strong> annual leave loading equal to 17.5% of his or her wage, for his or her normal weekly hours, calculated at the ordinary time rate of pay, whichever is the higher.</p><p><strong>(d)</strong> Provided that the maximum annual leave loading payable under this clause will be no greater than 17.5% of the weekly rate specified in the table below in respect of the five week period, or proportionate amount in respect of a lesser period or periods:</p><p>Effective Date Weekly Rate of Pay (FFPPOA) $1,973.19 1 July 2021 $2,012.65 1 July 2022 $2,052.91 1 July 2023 $2,093.97 1 July 2024</p><p><strong>(e)</strong> In addition to the ordinary pay as described in subclause 53.6, Manager and Administrative Workers employed by Royal Women’s Hospital or Royal Children’s Hospital will receive:</p><p><strong>(i)</strong> an amount of 17.5% loading on 4 weeks ordinary pay; or</p><p><strong>(ii)</strong> in the case of a shift worker, a payment in accordance with the following formula: penalties paid during the period of accrual, divided by the hours of work during the same period, multiplied by 52.</p><p><strong>(f)</strong> The amount in respect of subclause 53.7(e) above will be paid on the Employee’s anniversary date.</p><p><strong>53.8</strong> Annual leave in advance</p><p><strong>(a)</strong> Annual leave may be taken in advance, by mutual agreement between the Employer and Employee.</p><p><strong>(b)</strong> Where annual leave is taken in advance, a further period of annual leave will not commence to accrue until after the expiration of the twelve months (or a lesser period where necessary to align to the NES) in which annual leave had been taken before it accrued.</p><p><strong>(c)</strong> Where annual leave has been taken in advance by an Employee and:</p><p><strong>(i)</strong> the employment of the Employee is terminated before he or she has completed the year of employment in respect of which such annual leave has been taken; and</p><p><strong>(ii)</strong> the sum paid by the Employer to the Employee as ordinary pay for the annual leave so taken exceeds the sum that the Employer is required to pay to the Employee under subclauses 53.6 and 53.7 then the Employer will not be liable to make any payment to the Employee under subclause 53.6 or 53.7 and will be entitled to deduct the amount of such excess from any remuneration payable to the Employee upon termination of employment.</p><p><strong>53.9</strong> Cashing out of annual leave</p><p><strong>(a)</strong> Paid annual leave must not be cashed out except in accordance with an agreement under this subclause.</p><p><strong>(b)</strong> Each cashing out of a particular amount of paid annual leave must be the subject of a separate agreement.</p><p><strong>(c)</strong> An Employer and an Employee may agree in writing to the cashing out of a particular amount of accrued paid annual leave by the Employee.</p><p><strong>(d)</strong> The agreement under this subclause must:</p><p><strong>(i)</strong> state the amount of leave to be cashed out and the payment to be made to the employee for it;</p><p><strong>(ii)</strong> state date on which the payment is to be made; and</p><p><strong>(iii)</strong> be signed by the Employer and Employee and, if the Employee is under 18 years of age, by the Employee’s parent or guardian.</p><p><strong>(e)</strong> The payment must not be less than the amount that would have been payable had the Employee taken the leave at the time the payment is made.</p><p><strong>(f)</strong> An agreement under this subclause must not result in the Employee’s remaining accrued entitlement to paid annual leave being less than 4 weeks.</p><p><strong>(g)</strong> The maximum amount of accrued paid annual leave that may be cashed out in any period of 12 months is 2 weeks.</p><p><strong>(h)</strong> The Employer must keep a copy of any agreement under this subclause as an employee record.</p><p><strong>53.10</strong> Christmas/New Year Closure – DHSV This clause only applies to Dental Assistants employed by DHSV. Where the Employer closes one or more of its operations over the Christmas/New Year period and provided not less than 4 weeks’ notice in writing to affected Employees, such Employees will be afforded the option of utilising Annual Leave, Time in Lieu, Accrued Days Off for the period of closure or, in the event of insufficient credits, leave without pay.</p><p>Plain language terms: holidays, vacation, recreation leave, holiday pay.</p>',67)])])}const y=a(r,[["render",s]]);export{u as __pageData,y as default};
